import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

type FormState = {
  name: string;
  email: string;
  subject: string;
  message: string;
  subscribe: boolean;
};

const initialForm: FormState = {
  name: '',
  email: '',
  subject: '',
  message: '',
  subscribe: true
};

const Contact: React.FC = () => {
  const navigate = useNavigate();
  const [form, setForm] = useState<FormState>(initialForm);
  const [submitting, setSubmitting] = useState<boolean>(false);
  const [successId, setSuccessId] = useState<string | null>(null);
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const errors = useMemo(() => {
    const e: Record<string, string> = {};
    if (!form.name.trim()) e.name = 'Please enter your name';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) e.email = 'Enter a valid email';
    if (!form.subject.trim()) e.subject = 'Please enter a subject';
    if (form.message.trim().length < 10) e.message = 'Message should be at least 10 characters';
    return e;
  }, [form]);

  const onChange = (key: keyof FormState, value: string | boolean) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const handleSubmit = () => {
    setTouched({ name: true, email: true, subject: true, message: true });
    if (Object.keys(errors).length > 0) return;
    setSubmitting(true);
    setTimeout(() => {
      const ticket = `CW-${Math.floor(Math.random() * 900000 + 100000)}`;
      setSuccessId(ticket);
      setSubmitting(false);
      setForm(initialForm);
    }, 900);
  };

  return (
    <div className="min-h-screen">
      {/* Hero */}
      <section className="bg-gradient-to-br from-pink-500 via-fuchsia-600 to-indigo-600 text-white">
        <div className="container max-w-6xl mx-auto px-4 py-16">
          <div className="grid md:grid-cols-2 gap-8 items-center">
            <div>
              <h1 className="text-4xl md:text-5xl font-extrabold leading-tight">We’re here to help</h1>
              <p className="mt-3 text-white/90 text-lg">Whether it’s sizing, returns, or styling advice, our support stylists are just a message away.</p>
              <div className="mt-6 flex gap-3">
                <button onClick={() => navigate('/?chat=true')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow-md">Open live chat</button>
                <Link to="/about" className="px-4 py-2 rounded-lg bg-white text-gray-900 hover:bg-gray-100 transition shadow-md">About ChromoWear</Link>
              </div>
            </div>
            <div>
              <img src="https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=1400&q=80&auto=format&fit=crop" alt="Store interior" className="w-full h-72 md:h-96 object-cover rounded-xl shadow-md" />
            </div>
          </div>
        </div>
      </section>

      {/* Contact grid */}
      <section className="container max-w-6xl mx-auto px-4 py-10">
        {successId && (
          <div className="mb-6 bg-green-50 border border-green-200 text-green-800 rounded-xl p-4 flex items-center justify-between">
            <div>
              <p className="font-semibold">Message sent!</p>
              <p className="text-sm">Your support ticket ID is <span className="font-mono font-semibold">{successId}</span>. We’ll reply within 24 hours.</p>
            </div>
            <button onClick={() => setSuccessId(null)} className="px-4 py-2 rounded-lg bg-green-600 text-white hover:bg-green-500 transition">Dismiss</button>
          </div>
        )}
        <div className="grid lg:grid-cols-3 gap-6">
          {/* Form */}
          <div className="lg:col-span-2 bg-white rounded-xl shadow-md p-6">
            <h2 className="text-xl font-bold text-gray-900">Send us a message</h2>
            <div className="mt-4 grid md:grid-cols-2 gap-4">
              <div>
                <label className="text-sm text-gray-700">Name</label>
                <input value={form.name} onChange={(e) => onChange('name', e.target.value)} onBlur={() => setTouched((t) => ({ ...t, name: true }))} className="mt-1 w-full rounded-lg border border-gray-300 p-3 focus:outline-none focus:ring-2 focus:ring-blue-500" placeholder="Your full name" />
                {touched.name && errors.name && <p className="text-sm text-red-600 mt-1">{errors.name}</p>}
              </div>
              <div>
                <label className="text-sm text-gray-700">Email</label>
                <input value={form.email} onChange={(e) => onChange('email', e.target.value)} onBlur={() => setTouched((t) => ({ ...t, email: true }))} className="mt-1 w-full rounded-lg border border-gray-300 p-3 focus:outline-none focus:ring-2 focus:ring-blue-500" placeholder="you@example.com" />
                {touched.email && errors.email && <p className="text-sm text-red-600 mt-1">{errors.email}</p>}
              </div>
            </div>
            <div className="mt-4">
              <label className="text-sm text-gray-700">Subject</label>
              <input value={form.subject} onChange={(e) => onChange('subject', e.target.value)} onBlur={() => setTouched((t) => ({ ...t, subject: true }))} className="mt-1 w-full rounded-lg border border-gray-300 p-3 focus:outline-none focus:ring-2 focus:ring-blue-500" placeholder="How can we help?" />
              {touched.subject && errors.subject && <p className="text-sm text-red-600 mt-1">{errors.subject}</p>}
            </div>
            <div className="mt-4">
              <label className="text-sm text-gray-700">Message</label>
              <textarea value={form.message} onChange={(e) => onChange('message', e.target.value)} onBlur={() => setTouched((t) => ({ ...t, message: true }))} className="mt-1 w-full rounded-lg border border-gray-300 p-3 h-32 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500" placeholder="Tell us a bit more..." />
              {touched.message && errors.message && <p className="text-sm text-red-600 mt-1">{errors.message}</p>}
            </div>
            <div className="mt-4 flex items-center justify-between">
              <label className="flex items-center gap-2 text-sm text-gray-700">
                <input type="checkbox" checked={form.subscribe} onChange={(e) => onChange('subscribe', e.target.checked)} />
                Subscribe to ChromoClub for exclusive drops
              </label>
              <div className="flex gap-2">
                <button onClick={() => setForm(initialForm)} className="px-4 py-2 rounded-lg bg-gray-200 text-gray-900 hover:bg-gray-300 transition">Reset</button>
                <button onClick={() => handleSubmit()} disabled={submitting} className={`px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition ${submitting ? 'opacity-80 cursor-not-allowed' : ''}`}>{submitting ? 'Sending...' : 'Send message'}</button>
              </div>
            </div>
          </div>

          {/* Sidebar */}
          <div className="space-y-4">
            <div className="bg-white rounded-xl shadow-md p-6">
              <h3 className="font-semibold text-gray-900">Contact options</h3>
              <div className="mt-4 space-y-3">
                <button onClick={() => navigate('mailto:support@chromowear.com')} className="w-full flex items-center justify-between p-3 rounded-lg border hover:shadow-md transition">
                  <span>Email support</span>
                  <span className="text-sm text-gray-600">support@chromowear.com</span>
                </button>
                <button onClick={() => navigate('/?chat=true')} className="w-full flex items-center justify-between p-3 rounded-lg border hover:shadow-md transition">
                  <span>Live chat</span>
                  <span className="text-sm text-gray-600">Avg. reply 2m</span>
                </button>
                <button onClick={() => navigate('/?callback=true')} className="w-full flex items-center justify-between p-3 rounded-lg border hover:shadow-md transition">
                  <span>Request a callback</span>
                  <span className="text-sm text-gray-600">Mon–Fri</span>
                </button>
              </div>
            </div>
            <div className="bg-white rounded-xl shadow-md overflow-hidden">
              <img src="https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=1200&q=80&auto=format&fit=crop" alt="Storefront" className="w-full h-40 object-cover" />
              <div className="p-6">
                <h4 className="font-semibold text-gray-900">Visit our studio</h4>
                <p className="text-sm text-gray-600 mt-1">1200 Market St, Suite 300, San Francisco, CA</p>
                <div className="mt-3 flex gap-2">
                  <button onClick={() => navigate('/?visit=true')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Book a fitting</button>
                  <Link to="/about" className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition">Our story</Link>
                </div>
              </div>
            </div>
            <div className="bg-white rounded-xl shadow-md p-6">
              <h4 className="font-semibold text-gray-900">Quick links</h4>
              <ul className="mt-3 space-y-2 text-sm">
                <li><Link className="text-blue-600 hover:underline" to="/?category=Women">Women’s collection</Link></li>
                <li><Link className="text-blue-600 hover:underline" to="/?category=Men">Men’s collection</Link></li>
                <li><Link className="text-blue-600 hover:underline" to="/?category=Accessories">Accessories</Link></li>
                <li><Link className="text-blue-600 hover:underline" to="/about">Sustainability</Link></li>
              </ul>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Contact;

