const useProducts = () => {
  const [products] = useState<Product[]>(seedProducts());
  const [query, setQuery] = useState<string>('');
  const [activeCategory, setActiveCategory] = useState<string>('');
  const [sort, setSort] = useState<'popular' | 'price-asc' | 'price-desc' | 'new'>('popular');
  const [favorites, setFavorites] = useState<string[]>([]);

  // Load favorites from localStorage
  useEffect(() => {
    try {
      const raw = localStorage.getItem('cw:favorites');
      if (raw) setFavorites(JSON.parse(raw));
    } catch {
      setFavorites([]);
    }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('cw:favorites', JSON.stringify(favorites));
    } catch {
      // ignore persist errors
    }
  }, [favorites]);

  const categories = useMemo(() => {
    return Array.from(new Set(products.map((p) => p.category)));
  }, [products]);

  const filtered = useMemo(() => {
    let list = [...products];
    if (activeCategory) list = list.filter((p) => p.category === activeCategory);
    if (query.trim()) {
      const q = query.toLowerCase();
      list = list.filter((p) => `${p.name} ${p.description} ${p.tags.join(' ')}`.toLowerCase().includes(q));
    }
    if (sort === 'price-asc') list.sort((a, b) => a.price - b.price);
    if (sort === 'price-desc') list.sort((a, b) => b.price - a.price);
    if (sort === 'new') list.sort((a, b) => b.createdAt - a.createdAt);
    if (sort === 'popular') list.sort((a, b) => b.rating - a.rating);
    return list;
  }, [products, activeCategory, query, sort]);

  const featured = useMemo(() => products.filter((p) => p.featured), [products]);

  const getById = useCallback((id: string) => products.find((p) => p.id === id) || null, [products]);

  const toggleFavorite = useCallback((id: string) => {
    setFavorites((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  }, []);

  return {
    products,
    categories,
    query,
    setQuery,
    activeCategory,
    setActiveCategory,
    sort,
    setSort,
    filtered,
    featured,
    getById,
    favorites,
    toggleFavorite
  } as const;
};

export default useProducts;

