import { useCallback, useEffect, useMemo, useState } from 'react';

interface CartItem {
  id: string; // unique cart line id
  productId: string;
  name: string;
  price: number;
  image: string;
  qty: number;
  color?: string;
  size?: string;
}

const uid = () => Math.random().toString(36).slice(2, 10);

const useCart = () => {
  const [items, setItems] = useState<CartItem[]>([]);
  const [isOpen, setIsOpen] = useState<boolean>(false);

  // Load from storage
  useEffect(() => {
    try {
      const raw = localStorage.getItem('cw:cart');
      if (raw) setItems(JSON.parse(raw));
    } catch {
      setItems([]);
    }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('cw:cart', JSON.stringify(items));
    } catch {
      // ignore persist errors
    }
  }, [items]);

  const addToCart = useCallback((item: Omit<CartItem, 'id'>) => {
    setItems((prev) => {
      const match = prev.find((x) => x.productId === item.productId && x.color === item.color && x.size === item.size);
      if (match) {
        return prev.map((x) => (x === match ? { ...x, qty: Math.min(99, x.qty + item.qty) } : x));
      }
      return [...prev, { ...item, id: uid() }];
    });
    setIsOpen(true);
  }, []);

  const updateQty = useCallback((lineId: string, qty: number) => {
    setItems((prev) => prev.map((x) => (x.id === lineId ? { ...x, qty: Math.min(99, Math.max(1, qty)) } : x)));
  }, []);

  const removeItem = useCallback((lineId: string) => {
    setItems((prev) => prev.filter((x) => x.id !== lineId));
  }, []);

  const clearCart = useCallback(() => {
    setItems([]);
  }, []);

  const itemCount = useMemo(() => items.reduce((acc, x) => acc + x.qty, 0), [items]);
  const subtotal = useMemo(() => Number(items.reduce((acc, x) => acc + x.price * x.qty, 0).toFixed(2)), [items]);

  return {
    items,
    isOpen,
    setIsOpen,
    addToCart,
    updateQty,
    removeItem,
    clearCart,
    itemCount,
    subtotal
  } as const;
};

export default useCart;
